module top_module(
    Q  ,
    CLK,
    D  ,
    SCD,
    SCE
);output Q  ;
    input  CLK;
    input  D  ;
    input  SCD;
    input  SCE;


reg q_reg;
wire mux_out;
assign mux_out = (SCE == 1'b1)? SCD : D;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ ( posedge CLK or posedge dbg_halt)
       begin
	     q_reg <= mux_out;
       end

assign Q = q_reg;

endmodule
